type BuiltPerson = {
  name: string;
  age: number;
};

type NameStage = {
  setName(name: string): AgeStage;
};

type AgeStage = {
  setAge(age: number): BuildStage;
};

type BuildStage = {
  build(): BuiltPerson;
};

// Runtime implementation can satisfy all stages,
// but exposed type controls call order.
function createBuilder(): NameStage {
  const state: Partial<BuiltPerson> = {};

  const api = {
    setName(name: string) {
      state.name = name;
      return api;
    },
    setAge(age: number) {
      state.age = age;
      return api;
    },
    build() {
      return state as BuiltPerson;
    },
  };

  return api as unknown as NameStage;
}

const builder = createBuilder();

// ✅ OK
const person1 = builder
  .setName('x')
  .setAge(25)
  .build();

// ❌ Compile error: setAge does not exist on NameStage-returned builder start
const person2 = builder
  .setAge(25)
  .setName('x')
  .build();

// ❌ Compile error: build does not exist before age is set
const person3 = builder
  .setName('x')
  .build();
