  '/users/:userId',
  { wrongParam: '123' }
);

// ❌ COMPILE ERROR — missing 'postId'
// @ts-expect-error: Property 'postId' is missing
const routeBad2 = createRouteSafe(
  '/users/:userId/posts/:postId',
  { userId: '123' }
);

// ❌ COMPILE ERROR — extra parameter 'extra' not in template
