// ============================================================
// BUILDER STATE TRACKING
// ============================================================

/**
 * We track which methods have been called using a phantom type parameter.
 * 'Set' is a union of string literals representing completed steps.
 *
 * The trick: each method returns a Builder with the current step
 * ADDED to the Set type parameter, making it impossible to
 * call methods out of order or build with missing steps.
 */

// Represents all possible builder steps
type BuilderStep = 'name' | 'age';

// The final built product
interface Person {
  name: string;
  age: number;
}

/**
 * Builder interface where Set tracks which steps are complete.
 *
 * Method availability is controlled by conditional types:
 * - setName: only available if 'name' NOT yet in Set
 * - setAge:  only available if 'name' IS in Set (enforces order)
 *            AND 'age' NOT yet in Set
 * - build:   only available if BOTH 'name' AND 'age' are in Set
 *
 * Using 'never' as return type makes the method "disappear"
 * when the condition isn't met (calling it → type error).
 */
interface Builder<Set extends BuilderStep = never> {
  // setName is only available as first step (name not yet set)
  setName: 'name' extends Set
    ? never  // Already called → method effectively disappears
    : (name: string) => Builder<Set | 'name'>;

  // setAge requires name to be set first, and age not yet set
  setAge: 'name' extends Set
    ? 'age' extends Set
      ? never  // Already called
      : (age: number) => Builder<Set | 'age'>
    : never;   // name not set yet → can't call setAge

  // build requires both name AND age to be set
  build: 'name' extends Set
    ? 'age' extends Set
      ? () => Person  // Both set → build is available
      : never         // age missing
    : never;          // name missing
}

// ============================================================
// BUILDER IMPLEMENTATION
// ============================================================

