// State tracking using branded types
type RequiredFields = 'name' | 'age';

type BuilderState = {
  name: boolean;
  age: boolean;
};

type SetField<T extends keyof BuilderState> = 
  BuilderState & { [K in T]: true };

class Builder {
  private state: BuilderState = {
    name: false,
    age: false,
  };

  private data: { name?: string; age?: number } = {};

  setName(name: string): BuilderAfterSet<'name'> {
    this.data.name = name;
    this.state.name = true;
    return this as any;
  }

  setAge(age: number): BuilderAfterSet<'age'> {
    this.data.age = age;
    this.state.age = true;
    return this as any;
  }

  build(): { name: string; age: number } {
    if (!this.state.name || !this.state.age) {
      throw new Error('All fields must be set');
    }
    return this.data as { name: string; age: number };
  }
}

// Helper type to track what has been set
class BuilderAfterSet<T extends keyof BuilderState> {
  private state: BuilderState = {
    name: false,
    age: false,
  };

  private data: { name?: string; age?: number } = {};

  setName(name: string): T extends 'name' 
    ? never // already set
    : BuilderAfterSet<'name'> {
    throw new Error('Type system prevents this');
  }

  setAge(age: number): T extends 'age' 
    ? never 
    : BuilderAfterSet<'age'> {
    throw new Error('Type system prevents this');
  }

  build(): T extends 'name' & 'age' 
    ? { name: string; age: number } 
    : never {
    throw new Error('Type system prevents this');
  }
}

// Better: Use distinct types for each state
type EmptyBuilder = {
  setName(name: string): NameSetBuilder;
};

type NameSetBuilder = {
  setAge(age: number): CompleteBuilder;
  setName(name: string): never; // prevent duplicate
};

type CompleteBuilder = {
  build(): { name: string; age: number };
  setName(name: string): never;
  setAge(age: number): never;
};

function createBuilder(): EmptyBuilder {
  const data: { name?: string; age?: number } = {};

  const builder = {
    setName(name: string) {
      data.name = name;
      return {
        setAge(age: number) {
          data.age = age;
          return {
            build() {
              if (!data.name || data.age === undefined) {
                throw new Error('Missing fields');
