            setName: () => { throw new Error('Already set'); },
            setAge: () => { throw new Error('Already set'); }
          } as CompleteBuilder;
        },
        setName: () => { throw new Error('Already set'); }
      } as NameSetBuilder;
    }
  } as EmptyBuilder;

  return builder;
}

