### Alternative: Using Branded Types + Conditional Types (More Type-Safe)

```ts
type State = {
  hasName: boolean;
  hasAge: boolean;
};

type Builder<T extends State = { hasName: false; hasAge: false }> = {
  setName: T['hasName'] extends true 
    ? never 
    : (name: string) => Builder<{ hasName: true; hasAge: T['hasAge'] }>;

  setAge: T['hasAge'] extends true 
    ? never 
    : (age: number) => Builder<{ hasName: T['hasName']; hasAge: true }>;

  build: T extends { hasName: true; hasAge: true }
    ? () => { name: string; age: number }
    : never;
};

function createStrictBuilder(): Builder {
  const data: any = {};

  const makeBuilder = (state: State): any => ({
    setName: state.hasName ? undefined : (name: string) => {
      data.name = name;
      return makeBuilder({ ...state, hasName: true });
    },
    setAge: state.hasAge ? undefined : (age: number) => {
      data.age = age;
      return makeBuilder({ ...state, hasAge: true });
    },
    build: (state.hasName && state.hasAge) 
      ? () => ({ ...data }) 
      : undefined
  });

  return makeBuilder({ hasName: false, hasAge: false });
}
```

**Usage:**

```ts
