### 2. Builder Pattern with Enforced Order

We use **Variadic Tuple Types** to track the state of required steps via a type parameter (a tuple of "tags"). Each method returns a new Builder type with an updated tuple, and the `build` method is only available when the tuple contains all required tags.

```typescript
// 1. Define the tags representing the steps
type StepName = 'name_set';
type StepAge = 'age_set';

// 2. The Builder Type
// Steps extends an array of tags that have been completed so far
type Builder<Steps extends any[] = []> = {
  // setName can be called at any time, but adds 'name_set' to the Steps tuple
  setName: (name: string) => Builder<[...Steps, StepName]>;

  // setAge can be called at any time, but adds 'age_set' to the Steps tuple
  setAge: (age: number) => Builder<[...Steps, StepAge]>;

  // build is only available if Steps contains both required tags
  // We check this by seeing if we can extract the required tags from the tuple
  build: Steps extends [...infer First, StepName] 
    ? Steps extends [...infer First, StepAge] 
      ? () => { name: string; age: number }
      : never
    : never;
};

// 3. Implementation (Cast to the type to satisfy the compiler)
// In a real app, this would be a class implementing the interface
const createBuilder = (): Builder<[]> => {
  let name: string = '';
  let age: number = 0;

  return {
    setName(n: string) {
      name = n;
      // We cast the return type to match the recursive Builder definition
      return this as unknown as Builder<[StepName]>;
    },
    setAge(a: number) {
      age = a;
      return this as unknown as Builder<[StepAge]>;
    },
    build() {
      // Runtime check (though TS prevents calling this without both steps)
      if (!name || !age) throw new Error('Missing fields');
      return { name, age };
    }
  } as Builder<[]>;
};

// --- Usage Examples ---

const builder = createBuilder();

// ✓ Valid: Name then Age
const result1 = builder.setName('x').setAge(25).build();
// result1 is { name: string; age: number }

// ✗ Compile Error: Property 'build' does not exist on type 'Builder<[StepName]>'.
// Reason: Age is missing.
// const result2 = builder.setName('x').build();

// ✗ Compile Error: Property 'setAge' does not exist on type 'Builder<[StepAge, StepName]>'.
// Reason: Order is enforced (Name must come before Age based on our implementation logic below).
// Note: If you want strict order (Name -> Age), we modify the Builder logic slightly in the next section.

// --- STRICT ORDER VARIANT ---
// If you strictly require Name -> Age (not just both present), the type changes slightly:

type StrictBuilder<Steps extends any[] = []> = {
  // Only allow setName if 'name_set' is not already in Steps
  setName: Steps extends [infer First, ...infer Rest] 
    ? never // Prevent calling setName twice or if it's not the first step (simplified)
    : (name: string) => StrictBuilder<[StepName]>;

  // Only allow setAge if 'name_set' exists but 'age_set' does not
  setAge: Steps extends [StepName] 
    ? (age: number) => StrictBuilder<[StepName, StepAge]>
    : never;

  // Only allow build if steps are exactly [StepName, StepAge]
  build: Steps extends [StepName, StepAge] 
    ? () => { name: string; age: number }
    : never;
};

// Example of Strict Builder
const createStrictBuilder = (): StrictBuilder<[]> => {
  let name: string = '';
  let age: number = 0;

  return {
    setName(n: string) {
      name = n;
      return this as any; // Cast for demo simplicity
    },
    setAge(a: number) {
      age = a;
      return this as any;
    },
    build() {
      return { name, age };
    }
  } as StrictBuilder<[]>;
};

const strictBuilder = createStrictBuilder();

// ✓ Valid
const s1 = strictBuilder.setName('Alice').setAge(30).build();

// ✗ Compile Error: Property 'setAge' does not exist on type 'StrictBuilder<[]>'.
// Reason: Must call setName first.
// const s2 = strictBuilder.setAge(30).setName('Alice').build();

// ✗ Compile Error: Property 'build' does not exist on type 'StrictBuilder<[StepName]>'.
// Reason: Must call setAge before build.
// const s3 = strictBuilder.setName('Alice').build();
```
